// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract MembershipAirdrop {
    address private _owner;
    address private _pendingOwner;
    bool private _inProgress;

    mapping(address => uint256) public tierOf;
    mapping(address => bool) public claimed;
    mapping(address => uint256) public airdropCredits;
    mapping(address => uint256) public purchasedTokens;

    event TierSet(address indexed user, uint256 tier);
    event AirdropClaimed(address indexed user, uint256 credits);
    event TokensPurchased(address indexed user, uint256 amount);
    event Withdrawal(address indexed owner, uint256 amount);
    event OwnershipTransfer(address indexed previousOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not the owner");
        _;
    }

    modifier nonReentrant() {
        require(!_inProgress, "Reentrant call");
        _inProgress = true;
        _;
        _inProgress = false;
    }

    constructor() {
        _owner = msg.sender;
    }

    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "Invalid address");
        _pendingOwner = newOwner;
    }

    function acceptOwnership() public {
        require(msg.sender == _pendingOwner, "Not pending owner");
        _owner = msg.sender;
        delete _pendingOwner;
        emit OwnershipTransfer(msg.sender, _owner);
    }

    function setTier(address user, uint256 tier) public onlyOwner {
        require(tier >= 0, "Invalid tier");
        tierOf[user] = tier;
        emit TierSet(user, tier);
    }

    function claimAirdrop() public nonReentrant {
        require(tierOf[msg.sender] > 0, "User has no tier");
        require(!claimed[msg.sender], "Already claimed");
        uint256 credits = tierOf[msg.sender] * 100;
        airdropCredits[msg.sender] += credits;
        claimed[msg.sender] = true;
        emit AirdropClaimed(msg.sender, credits);
    }

    function purchaseTokens() public payable nonReentrant {
        require(msg.value > 0, "Value must be greater than 0");
        require(tierOf[msg.sender] > 0, "User has no tier");
        uint256 amount = (msg.value * 1000) / 1 ether;
        purchasedTokens[msg.sender] += amount;
        emit TokensPurchased(msg.sender, amount);
    }

    function withdrawAll() public onlyOwner {
        uint256 balance = address(this).balance;
        (bool sent, ) = _owner.call{value: balance}("");
        require(sent, "Failed to send Ether");
        emit Withdrawal(_owner, balance);
    }
}
